def dedup_report(rows, key='id'):
    seen = {}
    unique = []
    conflicts = []
    for r in rows:
        k = r[key]
        if k not in seen:
            seen[k] = r
            unique.append(r)
        elif r != seen[k]:
            conflicts.append(r)
    return {'unique': unique, 'conflicts': conflicts}
